// Typeform webhook payload'dan veri cikart
const body = $input.first().json.body || $input.first().json;

// Typeform form_response icinden email bul
const formResponse = body.form_response || body;
const answers = formResponse.answers || [];
const definition = formResponse.definition || {};
const formTitle = (definition.title || body.form_id || '').toLowerCase();

// Email'i bul (Typeform'da email field)
let email = '';
for (const ans of answers) {
  if (ans.type === 'email' || (ans.field && ans.field.type === 'email')) {
    email = (ans.email || ans.text || '').toLowerCase().trim();
    break;
  }
}

// Fallback: hidden fields'tan email
if (!email && formResponse.hidden) {
  email = (formResponse.hidden.email || '').toLowerCase().trim();
}

if (!email) {
  return [{ json: { error: 'Email bulunamadi', raw: body } }];
}

// Ad-Soyad bul (name fallback icin)
let fullName = '';
for (const ans of answers) {
  const fieldType = ans.field && ans.field.type;
  const fieldRef = (ans.field && ans.field.ref) || '';
  const fieldTitle = ((ans.field && ans.field.title) || '').toLowerCase();
  if (fieldType === 'short_text' && (fieldRef.includes('ad') || fieldRef.includes('name') || fieldTitle.includes('ad') || fieldTitle.includes('isim'))) {
    fullName = (ans.text || '').trim();
    if (fullName) break;
  }
}
if (!fullName && formResponse.hidden && formResponse.hidden.full_name) {
  fullName = String(formResponse.hidden.full_name).trim();
}

// Form tipini belirle
// Karekteristik envanter: skor kolonlari varsa veya form adinda 'karekteristik/karakteristik' geciyorsa
// Disipliner envanter: yazilim/dijital sanatlar alanlari varsa
let testType = 'karakteristik_envanter';
let discipline = null;

// Form ID veya title'a gore karar ver
// Bu degerleri kendi Typeform form ID'lerinize gore guncelleyin
const FORM_MAP = {
  // Karakteristik Envanter Testi (herkese zorunlu)
  'wfbPF1am': { testType: 'karakteristik_envanter', discipline: null },
  // Dijital Deneyim (UX/UI, etkilesim, AR/VR)
  'uPRgDzXs': { testType: 'disipliner_envanter', discipline: 'dijital_deneyim' },
  // Kreatif Yapim (grafik, illustrasyon, 3D, video, muzik)
  'c4R5Eidf': { testType: 'disipliner_envanter', discipline: 'kreatif_yapim' },
  // Dijital Urun (front/back-end, mobil, AI, DevOps)
  'KlpIjj9G': { testType: 'disipliner_envanter', discipline: 'dijital_urun' },
};

const formId = body.form_response?.form_id || body.form_id || '';
if (FORM_MAP[formId]) {
  testType = FORM_MAP[formId].testType;
  discipline = FORM_MAP[formId].discipline;
}

// Network ID
const networkId = formResponse.hidden?.network_id || formResponse.network_id || null;

// Skorlari cikart (karekteristik envanter icin)
let scores = {};
let totalScore = 0;

if (testType === 'karakteristik_envanter') {
  // Typeform variables/calculated fields'tan skorlari al
  const variables = formResponse.variables || [];
  for (const v of variables) {
    if (v.type === 'number') {
      scores[v.key] = v.number;
    }
  }
  // Hidden fields'tan skorlar
  if (formResponse.hidden) {
    const scoreKeys = ['birlestirici','caliskan','canli','challenger','cozumcu','gelecek_odakli','geleneksel','gozlemci','ilham_verici','inovatif','kendinden_emin','mantikli','pratik','sistemli','tecrubeli','titiz','tutkulu','yaratici'];
    for (const key of scoreKeys) {
      if (formResponse.hidden[key] !== undefined) {
        scores[key] = Number(formResponse.hidden[key]) || 0;
      }
    }
  }
  totalScore = Object.values(scores).reduce((sum, v) => sum + (Number(v) || 0), 0);
}

// Disipliner envanter icin cevaplari topla
let answersData = {};
if (testType === 'disipliner_envanter') {
  for (const ans of answers) {
    const fieldTitle = ans.field?.title || ans.field?.id || '';
    const value = ans.text || ans.choice?.label || (ans.choices?.labels || []).join(', ') || ans.email || '';
    if (fieldTitle) answersData[fieldTitle] = value;
  }
}

return [{
  json: {
    email,
    full_name: fullName || null,
    test_type: testType,
    discipline,
    network_id: networkId,
    scores,
    total_score: totalScore,
    answers: testType === 'karakteristik_envanter' ? {} : answersData,
    submitted_at: formResponse.submitted_at || new Date().toISOString(),
    response_type: formResponse.response_type || 'completed',
  }
}];

const input = $input.first().json;
const apiResponse = input;

if (apiResponse.success) {
  return [{
    json: {
      status: 'ok',
      message: `Envanter testi kaydedildi: ${input.email || 'unknown'}`,
      task_updated: apiResponse.task_updated || false,
    }
  }];
} else {
  return [{
    json: {
      status: 'error',
      message: apiResponse.error || 'API hatasi',
      email: input.email,
    }
  }];
}
